const body = $input.first().json.body || $input.first().json;

const hostname     = body.vm_name || body.hostname || 'unknown';
const location     = body.location || 'not set';
const primaryIp    = (body.ip && body.ip.primary) ? body.ip.primary : 'unknown';
const ram          = body.ram  || {};
const disk         = (body.disk && body.disk.root) ? body.disk.root : {};
const hasIssues    = body.has_issues === true;
const issues       = body.resource_issues || [];
const timestamp    = body.timestamp || '';
const ownerName    = body.owner  ? body.owner.name  : '';
const ownerEmail   = body.owner  ? body.owner.email : '';
const ccEmails     = body.cc_emails || '';
const networkVer   = body.network_version || '';

const ramUsedPct  = parseFloat(ram.usage_pct  || 0);
const diskUsedPct = parseFloat(disk.usage_pct || 0);
const ramFreeGb   = parseFloat(ram.free_gb    || 0).toFixed(1);
const ramTotalGb  = parseFloat(ram.total_gb   || 0).toFixed(1);
const ramUsedGb   = parseFloat(ram.used_gb    || 0).toFixed(1);
const diskFreeGb  = parseFloat(disk.free_gb   || 0).toFixed(1);
const diskTotalGb = parseFloat(disk.total_gb  || 0).toFixed(1);
const diskUsedGb  = parseFloat(disk.used_gb   || 0).toFixed(1);

const maxPct = Math.max(ramUsedPct, diskUsedPct);
let severity = 'OK';
let sevColor = '#27ae60';
if      (maxPct >= 90) { severity = 'CRITICAL'; sevColor = '#c0392b'; }
else if (maxPct >= 80) { severity = 'WARNING';  sevColor = '#e67e22'; }
else if (maxPct >= 70) { severity = 'NOTICE';   sevColor = '#f39c12'; }
else if (maxPct >= 60) { severity = 'INFO';     sevColor = '#2980b9'; }

const activeIssues = issues.filter(function(i){ return i.type && i.type !== 'none'; });

var issueLines = '';
if (activeIssues.length > 0) {
  for (var i = 0; i < activeIssues.length; i++) {
    var iss = activeIssues[i];
    issueLines += '[' + (iss.severity||'').toUpperCase() + '] ' + iss.message;
    if (iss.tier) issueLines += ' (repeats every ' + iss.alert_interval_hours + 'h)';
    issueLines += '\n';
  }
} else {
  issueLines = 'All resources within normal limits';
}

function bar(pct) {
  var f = Math.min(Math.round(pct/10),10);
  var s=''; for(var i=0;i<f;i++) s+='|'; for(var i=0;i<10-f;i++) s+='.';
  return '['+s+'] '+pct+'%';
}

function tgBar(pct) {
  var filled = Math.min(Math.round(pct / 5), 20);
  var s = '';
  for (var i = 0; i < filled; i++) s += '█';
  for (var i = 0; i < 20 - filled; i++) s += '░';
  return s;
}
function tgSevBadge(sev) {
  if (sev === 'CRITICAL') return '🟥 CRITICAL';
  if (sev === 'WARNING')  return '🟧 WARNING';
  if (sev === 'NOTICE')   return '🟡 NOTICE';
  if (sev === 'INFO')     return '🔵 INFO';
  return '🟢 OK';
}
function tgSevIcon(sev) {
  if (sev === 'CRITICAL') return '🚨';
  if (sev === 'WARNING')  return '⚠️';
  if (sev === 'NOTICE')   return '🟡';
  if (sev === 'INFO')     return '🔵';
  return '✅';
}
var div = '──────────────────────';
var tgLines = [
  tgSevIcon(severity) + ' <b>VM INFRASTRUCTURE MONITOR</b>',
  div,
  '💻 <b>' + hostname + '</b>   📍 ' + location,
  '🌐 <b>IP:</b> ' + primaryIp + '   🕐 ' + timestamp,
  '👤 <b>Owner:</b> ' + ownerName + ' (' + ownerEmail + ')   🔗 <b>Network:</b> ' + networkVer,
  '<b>Status:</b> ' + tgSevBadge(severity),
  div,
  '💾 <b>RAM USAGE</b>',
  '<code>' + tgBar(ramUsedPct) + '</code>  <b>' + ramUsedPct + '%</b>',
  'Used: <b>' + ramUsedGb + ' GB</b>  |  Free: <b>' + ramFreeGb + ' GB</b>  |  Total: <b>' + ramTotalGb + ' GB</b>',
  '',
  '💿 <b>DISK USAGE (/)</b>',
  '<code>' + tgBar(diskUsedPct) + '</code>  <b>' + diskUsedPct + '%</b>',
  'Used: <b>' + diskUsedGb + ' GB</b>  |  Free: <b>' + diskFreeGb + ' GB</b>  |  Total: <b>' + diskTotalGb + ' GB</b>',
  div,
];
if (activeIssues.length > 0) {
  tgLines.push('⚠️ <b>ACTIVE ISSUES</b>');
  for (var i = 0; i < activeIssues.length; i++) {
    var iss = activeIssues[i];
    var issIcon = (iss.severity==='critical')?'🟥':(iss.severity==='warning')?'🟧':(iss.severity==='notice')?'🟡':'🔵';
    var tierNote = iss.tier ? ' <i>(repeats every ' + iss.alert_interval_hours + 'h)</i>' : '';
    tgLines.push(issIcon + ' ' + iss.message + tierNote);
  }
} else {
  tgLines.push('🟢 <b>All resources within normal limits</b>');
}
tgLines.push(div);
tgLines.push('<i>VM Metrics Reporter — Auto-generated alert</i>');

var subIcon=(severity==='CRITICAL')?'[CRITICAL]':(severity==='WARNING')?'[WARNING]':(severity==='NOTICE')?'[NOTICE]':(severity==='INFO')?'[INFO]':'[OK]';

return [{json:{
  hostname, location, primaryIp, timestamp,
  hasIssues, severity, sevColor,
  ramUsedPct, diskUsedPct,
  ramUsedGb, ramFreeGb, ramTotalGb,
  diskUsedGb, diskFreeGb, diskTotalGb,
  issueLines: issueLines.trim(),
  tgMessage: tgLines.join('\n'),
  emailSubject: subIcon+' VM Alert: '+hostname+' | '+timestamp,
  ramBar: bar(ramUsedPct),
  diskBar: bar(diskUsedPct),
  ownerName, ownerEmail, ccEmails, networkVer
}}];

const body = $input.first().json.body || $input.first().json;

const ram  = body.ram  || {};
const disk = (body.disk && body.disk.root) ? body.disk.root : {};
const ip   = body.ip   || {};
const today = (body.report_date || new Date().toISOString().slice(0, 10));

const ramUsedPct  = parseFloat(ram.usage_pct  || 0);
const diskUsedPct = parseFloat(disk.usage_pct || 0);
const maxPct = Math.max(ramUsedPct, diskUsedPct);
let severity = 'OK';
if      (maxPct >= 90) severity = 'CRITICAL';
else if (maxPct >= 80) severity = 'WARNING';
else if (maxPct >= 70) severity = 'NOTICE';
else if (maxPct >= 60) severity = 'INFO';

const vmName     = body.vm_name || 'unknown';
const primaryIp  = (ip.primary || ip.all) || 'unknown';
const location   = body.location        || '';
const networkVer = body.network_version || '';
const timestamp  = body.timestamp       || '';
const ownerName  = body.owner ? body.owner.name  : '';
const ownerEmail = body.owner ? body.owner.email : '';
const ccEmails   = body.cc_emails || '';

// Build the full data object to store as JSON
const vmData = {
  vm_name:       vmName,
  primaryIp:     primaryIp,
  hostname:      vmName,
  location:      location,
  network:       networkVer,
  severity:      severity,
  ramUsedPct:    ramUsedPct,
  ramUsedGb:     parseFloat(ram.used_gb    || 0).toFixed(1),
  ramFreeGb:     parseFloat(ram.free_gb    || 0).toFixed(1),
  ramTotalGb:    parseFloat(ram.total_gb   || 0).toFixed(1),
  diskUsedPct:   diskUsedPct,
  diskUsedGb:    parseFloat(disk.used_gb   || 0).toFixed(1),
  diskFreeGb:    parseFloat(disk.free_gb   || 0).toFixed(1),
  diskTotalGb:   parseFloat(disk.total_gb  || 0).toFixed(1),
  timestamp:     timestamp,
  report_date:   today,
  ownerName:     ownerName,
  ownerEmail:    ownerEmail,
  ccEmails:      ccEmails,
  activeIssues:  (body.resource_issues || []).filter(i => i.type && i.type !== 'none')
};

return [{ json: {
  ip: primaryIp,
  data: JSON.stringify(vmData).replace(/'/g, "''"),
  vm_name: vmName,
  report_date: today
}}];

const machines = {};
for (const row of $input.all()) {
  try {
    const m = JSON.parse(row.json.data);
    machines[m.primaryIp || row.json.ip] = m;
  } catch(e) {}
}

const ipList = Object.keys(machines);
if (ipList.length === 0) return [{ json: { noData: true } }];

const list = ipList.map(ip => machines[ip]);
const SEV_ORDER = { CRITICAL: 0, WARNING: 1, NOTICE: 2, INFO: 3, OK: 4 };
list.sort((a, b) => (SEV_ORDER[a.severity] ?? 5) - (SEV_ORDER[b.severity] ?? 5));

const now = new Date().toLocaleString('en-GB', {
  weekday: 'long', day: '2-digit', month: 'long', year: 'numeric',
  hour: '2-digit', minute: '2-digit'
});

const vmCount   = list.length;
const critCount = list.filter(m => m.severity === 'CRITICAL').length;
const warnCount = list.filter(m => m.severity === 'WARNING').length;
const okCount   = list.filter(m => m.severity === 'OK').length;

function pctColor(pct) {
  if (pct >= 90) return '#b91c1c';
  if (pct >= 80) return '#c2410c';
  if (pct >= 70) return '#b45309';
  if (pct >= 60) return '#1d4ed8';
  return '#15803d';
}

function barCell(pct, gb) {
  const clr = pctColor(pct);
  const w = Math.min(pct, 100);
  return '<td style="padding:16px 18px;vertical-align:middle">'
    + '<table cellpadding="0" cellspacing="0"><tr>'
    + '<td style="padding-right:10px">'
      + '<p style="margin:0;font-size:16px;font-weight:800;color:' + clr + '">' + pct + '%</p>'
      + '<p style="margin:3px 0 0;font-size:12px;color:#9ca3af">' + gb + ' GB</p>'
    + '</td>'
    + '<td valign="middle">'
      + '<table cellpadding="0" cellspacing="0" width="64" style="margin-top:2px"><tr>'
        + '<td bgcolor="#e5e7eb" style="border-radius:3px;height:6px;overflow:hidden;width:64px">'
          + '<table cellpadding="0" cellspacing="0" width="' + w + '%"><tr>'
            + '<td bgcolor="' + clr + '" style="height:6px;border-radius:3px;font-size:1px">&nbsp;</td>'
          + '</tr></table>'
        + '</td>'
      + '</tr></table>'
    + '</td>'
    + '</tr></table>'
  + '</td>';
}

function badgeStyle(sev) {
  if (sev === 'CRITICAL') return 'background:#fee2e2;color:#b91c1c';
  if (sev === 'WARNING')  return 'background:#ffedd5;color:#c2410c';
  if (sev === 'NOTICE')   return 'background:#fef3c7;color:#b45309';
  if (sev === 'INFO')     return 'background:#dbeafe;color:#1d4ed8';
  return                         'background:#dcfce7;color:#15803d';
}

function rowBg(sev, index) {
  if (index % 2 !== 0) return '#fafafa';
  if (sev === 'CRITICAL') return '#fff5f5';
  if (sev === 'WARNING')  return '#fffbf5';
  return '#ffffff';
}

let rows = '';
for (let i = 0; i < list.length; i++) {
  const m = list[i];
  rows +=
    '<tr bgcolor="' + rowBg(m.severity, i) + '">'
    + '<td style="padding:16px 18px;vertical-align:middle">'
      + '<p style="margin:0;font-size:16px;font-weight:800;color:#111827">' + (m.hostname || m.vm_name) + '</p>'
    + '</td>'
    + '<td style="padding:16px 18px;vertical-align:middle">'
      + '<p style="margin:0;font-size:15px;font-family:monospace;color:#4b5563">' + m.primaryIp + '</p>'
    + '</td>'
    + barCell(m.ramUsedPct, m.ramUsedGb)
    + barCell(m.diskUsedPct, m.diskUsedGb)
    + '<td style="padding:16px 18px;vertical-align:middle;text-align:center">'
      + '<span style="display:inline-block;padding:8px 20px;border-radius:6px;font-size:17px;font-weight:900;letter-spacing:0.5px;' + badgeStyle(m.severity) + '">' + m.severity + '</span>'
    + '</td>'
    + '</tr>';
}

const html =
  '<!DOCTYPE html><html><head><meta charset="UTF-8"></head>'
  + '<body style="margin:0;padding:0;background:#f3f4f6;font-family:Arial,Helvetica,sans-serif">'
  + '<table width="100%" cellpadding="0" cellspacing="0" bgcolor="#f3f4f6"><tr><td style="padding:28px 12px">'
  + '<table width="100%" cellpadding="0" cellspacing="0" style="border-radius:8px;overflow:hidden;border:1px solid #d1d5db;background:#ffffff">'

  + '<tr><td style="padding:28px 36px;border-bottom:1px solid #e5e7eb">'
    + '<p style="margin:0;font-size:26px;font-weight:800;color:#111827">' + now + '</p>'
  + '</td></tr>'

  + '<tr><td>'
    + '<table width="100%" cellpadding="0" cellspacing="0"><tr>'
      + '<td width="25%" style="padding:22px 0;text-align:center;border-right:1px solid #e5e7eb;border-bottom:1px solid #e5e7eb">'
        + '<p style="margin:0 0 8px;font-size:14px;font-weight:700;color:#6b7280;text-transform:uppercase;letter-spacing:0.6px">Total</p>'
        + '<p style="margin:0;font-size:36px;font-weight:900;color:#111827">' + vmCount + '</p>'
      + '</td>'
      + '<td width="25%" style="padding:22px 0;text-align:center;border-right:1px solid #e5e7eb;border-bottom:1px solid #e5e7eb">'
        + '<p style="margin:0 0 8px;font-size:14px;font-weight:700;color:#6b7280;text-transform:uppercase;letter-spacing:0.6px">Critical</p>'
        + '<p style="margin:0;font-size:36px;font-weight:900;color:' + (critCount > 0 ? '#b91c1c' : '#9ca3af') + '">' + critCount + '</p>'
      + '</td>'
      + '<td width="25%" style="padding:22px 0;text-align:center;border-right:1px solid #e5e7eb;border-bottom:1px solid #e5e7eb">'
        + '<p style="margin:0 0 8px;font-size:14px;font-weight:700;color:#6b7280;text-transform:uppercase;letter-spacing:0.6px">Warning</p>'
        + '<p style="margin:0;font-size:36px;font-weight:900;color:' + (warnCount > 0 ? '#c2410c' : '#9ca3af') + '">' + warnCount + '</p>'
      + '</td>'
      + '<td width="25%" style="padding:22px 0;text-align:center;border-bottom:1px solid #e5e7eb">'
        + '<p style="margin:0 0 8px;font-size:14px;font-weight:700;color:#6b7280;text-transform:uppercase;letter-spacing:0.6px">OK</p>'
        + '<p style="margin:0;font-size:36px;font-weight:900;color:' + (okCount === vmCount ? '#15803d' : '#9ca3af') + '">' + okCount + '</p>'
      + '</td>'
    + '</tr></table>'
  + '</td></tr>'

  + '<tr><td>'
    + '<table width="100%" cellpadding="0" cellspacing="0">'
      + '<tr bgcolor="#f1f5f9">'
        + '<td width="28%" style="padding:14px 18px;font-size:14px;font-weight:700;color:#374151;text-transform:uppercase;border-bottom:2px solid #d1d5db">Hostname</td>'
        + '<td width="22%" style="padding:14px 18px;font-size:14px;font-weight:700;color:#374151;text-transform:uppercase;border-bottom:2px solid #d1d5db">IP</td>'
        + '<td width="18%" style="padding:14px 18px;font-size:14px;font-weight:700;color:#374151;text-transform:uppercase;border-bottom:2px solid #d1d5db">RAM</td>'
        + '<td width="18%" style="padding:14px 18px;font-size:14px;font-weight:700;color:#374151;text-transform:uppercase;border-bottom:2px solid #d1d5db">Disk</td>'
        + '<td width="14%" style="padding:14px 18px;font-size:14px;font-weight:700;color:#374151;text-transform:uppercase;border-bottom:2px solid #d1d5db;text-align:center">Status</td>'
      + '</tr>'
      + rows
    + '</table>'
  + '</td></tr>'

  + '</table></td></tr></table>'
  + '</body></html>';

// Telegram summary
const div = '──────────────────────';
const sevIcon = sev => ({ CRITICAL:'🟥', WARNING:'⚠️', NOTICE:'🟡', INFO:'🔵', OK:'✅' })[sev] || '✅';
const tgBar = pct => { const f = Math.min(Math.round(pct / 5), 20); return '█'.repeat(f) + '░'.repeat(20 - f); };

let tgLines = [
  (critCount > 0 ? '🚨' : warnCount > 0 ? '⚠️' : '✅') + ' <b>VM DAILY CONSOLIDATED REPORT</b>',
  div,
  '📊 <b>' + vmCount + ' servers</b>  |  🔴 ' + critCount + ' critical  |  🟠 ' + warnCount + ' warning  |  🟢 ' + okCount + ' ok',
  div
];
for (const m of list) {
  tgLines.push(sevIcon(m.severity) + ' <b>' + (m.hostname || m.vm_name) + '</b>  <code>' + m.primaryIp + '</code>');
  tgLines.push('💾 RAM: <code>' + tgBar(m.ramUsedPct) + '</code> ' + m.ramUsedPct + '%');
  tgLines.push('💿 Disk: <code>' + tgBar(m.diskUsedPct) + '</code> ' + m.diskUsedPct + '%');
  tgLines.push('');
}
tgLines.push('<i>VM Metrics Reporter — ' + now + '</i>');

const subjectPrefix = critCount > 0 ? '[' + critCount + ' CRITICAL] ' : warnCount > 0 ? '[WARNING] ' : '[OK] ';

return [{ json: {
  noData: false,
  emailTo: list[0].ownerEmail || '',
  emailSubject: subjectPrefix + 'Daily VM Report — ' + vmCount + ' servers — ' + now,
  htmlBody: html,
  tgMessage: tgLines.join('\n')
}}];
